import{_ as a,c as t,o as n,a1 as o}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"OpenAI: Consulta de cuota | opencode-mystatus","description":"Aprende a usar /mystatus para consultar cuotas OpenAI de Plus/Team/Pro. Entiende límites de 3 horas y 24 horas, ventanas primarias y secundarias, y evita restricciones de desarrollo.","frontmatter":{"title":"OpenAI: Consulta de cuota | opencode-mystatus","sidebarTitle":"OpenAI","subtitle":"Consulta de cuota de OpenAI: límites de 3 horas y 24 horas","description":"Aprende a usar /mystatus para consultar cuotas OpenAI de Plus/Team/Pro. Entiende límites de 3 horas y 24 horas, ventanas primarias y secundarias, y evita restricciones de desarrollo.","tags":["OpenAI","consulta de cuota","cuota de API"],"prerequisite":["start-quick-start","start-understanding-output"],"order":1},"headers":[],"relativePath":"es/vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"es/vbgate/opencode-mystatus/platforms/openai-usage/index.md"}'),r={name:"es/vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function s(i,e,l,d,c,u){return n(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="consulta-de-cuota-de-openai-limites-de-3-horas-y-24-horas" tabindex="-1">Consulta de cuota de OpenAI: límites de 3 horas y 24 horas <a class="header-anchor" href="#consulta-de-cuota-de-openai-limites-de-3-horas-y-24-horas" aria-label="Permalink to &quot;Consulta de cuota de OpenAI: límites de 3 horas y 24 horas&quot;">​</a></h1><h2 id="lo-que-aprenderas" tabindex="-1">Lo que aprenderás <a class="header-anchor" href="#lo-que-aprenderas" aria-label="Permalink to &quot;Lo que aprenderás&quot;">​</a></h2><ul><li>Usar <code>/mystatus</code> para consultar la cuota de suscripciones OpenAI Plus/Team/Pro</li><li>Comprender la información de límites de 3 horas y 24 horas en la salida</li><li>Entender la diferencia entre ventana principal y ventana secundaria</li><li>Conocer cómo manejar el token expirado</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Las llamadas a la API de OpenAI tienen límites, después de excederlos se restringirá temporalmente el acceso. Pero no sabes:</p><ul><li>¿Cuánta cuota te queda actualmente?</li><li>¿Cuál de los límites de 3 horas o 24 horas se está usando?</li><li>¿Cuándo se restablecerá?</li><li>¿Por qué a veces ves datos de dos ventanas?</li></ul><p>Si no capturas esta información a tiempo, puede afectar tu progreso al usar ChatGPT para escribir código o hacer proyectos.</p><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><p>Cuando tú:</p><ul><li>Necesitas usar frecuentemente la API de OpenAI para desarrollar</li><li>Notas que las respuestas son más lentas o estás siendo limitado</li><li>Quieres conocer el uso de la cuenta de equipo</li><li>Quieres saber cuándo se renovará la cuota</li></ul><h2 id="enfoque-central" tabindex="-1">Enfoque central <a class="header-anchor" href="#enfoque-central" aria-label="Permalink to &quot;Enfoque central&quot;">​</a></h2><p>OpenAI tiene dos ventanas de limitación para las llamadas a la API:</p><table tabindex="0"><thead><tr><th>Tipo de ventana</th><th>Duración</th><th>Función</th></tr></thead><tbody><tr><td><strong>Ventana principal</strong> (primary)</td><td>Devuelta por el servidor OpenAI</td><td>Evitar llamadas masivas en poco tiempo</td></tr><tr><td><strong>Ventana secundaria</strong> (secondary)</td><td>Devuelta por el servidor OpenAI (puede no existir)</td><td>Evitar uso excesivo a largo plazo</td></tr></tbody></table><p>mystatus consulta paralelamente estas dos ventanas y muestra各自的:</p><ul><li>Porcentaje usado</li><li>Barra de progreso de cuota restante</li><li>Tiempo hasta el restablecimiento</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La duración de la ventana es devuelta por el servidor OpenAI, puede variar según diferentes tipos de suscripción (Plus, Team, Pro).</p></div><h2 id="sigue-los-pasos" tabindex="-1">Sigue los pasos <a class="header-anchor" href="#sigue-los-pasos" aria-label="Permalink to &quot;Sigue los pasos&quot;">​</a></h2><h3 id="paso-1-ejecuta-el-comando-de-consulta" tabindex="-1">Paso 1: Ejecuta el comando de consulta <a class="header-anchor" href="#paso-1-ejecuta-el-comando-de-consulta" aria-label="Permalink to &quot;Paso 1: Ejecuta el comando de consulta&quot;">​</a></h3><p>En OpenCode, ingresa <code>/mystatus</code>, el sistema consultará automáticamente las cuotas de todas las plataformas configuradas.</p><p><strong>Lo que deberías ver</strong>: Incluye información de cuota de plataformas como OpenAI, Zhipu AI, Z.ai, Copilot, Google Cloud (dependiendo de qué plataformas hayas configurado).</p><h3 id="paso-2-encuentra-la-seccion-de-openai" tabindex="-1">Paso 2: Encuentra la sección de OpenAI <a class="header-anchor" href="#paso-2-encuentra-la-seccion-de-openai" aria-label="Permalink to &quot;Paso 2: Encuentra la sección de OpenAI&quot;">​</a></h3><p>En la salida, busca la sección <code>## OpenAI Account Quota</code>.</p><p><strong>Lo que deberías ver</strong>: Contenido similar a este:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>███████████████░░░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="paso-3-interpreta-la-informacion-de-la-ventana-principal" tabindex="-1">Paso 3: Interpreta la información de la ventana principal <a class="header-anchor" href="#paso-3-interpreta-la-informacion-de-la-ventana-principal" aria-label="Permalink to &quot;Paso 3: Interpreta la información de la ventana principal&quot;">​</a></h3><p><strong>Ventana principal</strong> (primary_window) generalmente muestra:</p><ul><li><strong>Nombre de ventana</strong>: Como <code>3-hour limit</code> o <code>24-hour limit</code></li><li><strong>Barra de progreso</strong>: Visualiza intuitivamente la proporción de cuota restante</li><li><strong>Porcentaje restante</strong>: Como <code>60% remaining</code></li><li><strong>Tiempo de restablecimiento</strong>: Como <code>Resets in: 2h 30m</code></li></ul><p><strong>Lo que deberías ver</strong>:</p><ul><li>El nombre de la ventana muestra la duración (3 horas / 24 horas)</li><li>Cuanto más llena la barra de progreso, más restante hay, cuanto más vacía, más rápido se agotará</li><li>El tiempo de restablecimiento es una cuenta regresiva, cuando llegue a cero se renovará la cuota</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Si ves el mensaje <code>Limit reached!</code>, significa que la cuota de la ventana actual se ha agotado, necesitas esperar el restablecimiento.</p></div><h3 id="paso-4-revisa-la-ventana-secundaria-si-existe" tabindex="-1">Paso 4: Revisa la ventana secundaria (si existe) <a class="header-anchor" href="#paso-4-revisa-la-ventana-secundaria-si-existe" aria-label="Permalink to &quot;Paso 4: Revisa la ventana secundaria (si existe)&quot;">​</a></h3><p>Si OpenAI devuelve datos de ventana secundaria, verás:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>████████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>:</p><ul><li>La ventana secundaria muestra otra dimensión temporal de la cuota (generalmente 24 horas)</li><li>Puede tener un porcentaje restante diferente al de la ventana principal</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>La ventana secundaria es un pool de cuota independiente, agotar la ventana principal no afecta a la secundaria, y viceversa.</p></div><h3 id="paso-5-revisa-el-tipo-de-suscripcion" tabindex="-1">Paso 5: Revisa el tipo de suscripción <a class="header-anchor" href="#paso-5-revisa-el-tipo-de-suscripcion" aria-label="Permalink to &quot;Paso 5: Revisa el tipo de suscripción&quot;">​</a></h3><p>En la línea <code>Account</code> puedes ver el tipo de suscripción:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                   ^^^^^</span></span>
<span class="line"><span>                                   Tipo de suscripción</span></span></code></pre></div><p><strong>Tipos de suscripción comunes</strong>:</p><ul><li><code>plus</code>: Suscripción personal Plus</li><li><code>team</code>: Suscripción de equipo/organización</li><li><code>pro</code>: Suscripción Pro</li></ul><p><strong>Lo que deberías ver</strong>:</p><ul><li>Tu tipo de cuenta se muestra entre paréntesis después del correo</li><li>Diferentes tipos pueden tener diferentes límites</li></ul><h2 id="punto-de-control-✅" tabindex="-1">Punto de control ✅ <a class="header-anchor" href="#punto-de-control-✅" aria-label="Permalink to &quot;Punto de control ✅&quot;">​</a></h2><p>Verifica que has entendido:</p><table tabindex="0"><thead><tr><th>Escenario</th><th>Lo que deberías ver</th></tr></thead><tbody><tr><td>Ventana principal con 60% restante</td><td>Barra de progreso aproximadamente 60% llena, muestra <code>60% remaining</code></td></tr><tr><td>Se restablecerá en 2.5 horas</td><td>Muestra <code>Resets in: 2h 30m</code></td></tr><tr><td>Límite alcanzado</td><td>Muestra <code>Limit reached!</code></td></tr><tr><td>Hay ventana secundaria</td><td>La ventana principal y la secundaria cada una tienen una línea de datos</td></tr></tbody></table><h2 id="advertencias-de-errores-comunes" tabindex="-1">Advertencias de errores comunes <a class="header-anchor" href="#advertencias-de-errores-comunes" aria-label="Permalink to &quot;Advertencias de errores comunes&quot;">​</a></h2><h3 id="❌-error-de-operacion-no-refrescar-cuando-el-token-expira" tabindex="-1">❌ Error de operación: No refrescar cuando el token expira <a class="header-anchor" href="#❌-error-de-operacion-no-refrescar-cuando-el-token-expira" aria-label="Permalink to &quot;❌ Error de operación: No refrescar cuando el token expira&quot;">​</a></h3><p><strong>Síntoma de error</strong>: Ves el mensaje <code>⚠️ OAuth 授权已过期</code> (chino) o <code>⚠️ OAuth token expired</code> (inglés)</p><p><strong>Causa</strong>: El token OAuth ha expirado (duración específica controlada por el servidor), después de expirar no se puede consultar la cuota.</p><p><strong>Operación correcta</strong>:</p><ol><li>Vuelve a iniciar sesión en OpenAI en OpenCode</li><li>El token se refrescará automáticamente</li><li>Ejecuta <code>/mystatus</code> nuevamente para consultar</li></ol><h3 id="❌-error-de-operacion-confundir-ventana-principal-y-ventana-secundaria" tabindex="-1">❌ Error de operación: Confundir ventana principal y ventana secundaria <a class="header-anchor" href="#❌-error-de-operacion-confundir-ventana-principal-y-ventana-secundaria" aria-label="Permalink to &quot;❌ Error de operación: Confundir ventana principal y ventana secundaria&quot;">​</a></h3><p><strong>Síntoma de error</strong>: Piensas que solo hay un límite de cuota, pero la ventana principal se agota y la secundaria sigue en uso</p><p><strong>Causa</strong>: Las dos ventanas son pools de cuota independientes.</p><p><strong>Operación correcta</strong>:</p><ul><li>Presta atención al tiempo de restablecimiento de cada ventana</li><li>La ventana principal se restablece rápido, la secundaria se restablece lento</li><li>Distribuye el uso razonablemente, evita que alguna ventana se mantenga en exceso</li></ul><h3 id="❌-error-de-operacion-ignorar-el-id-de-cuenta-de-equipo" tabindex="-1">❌ Error de operación: Ignorar el ID de cuenta de equipo <a class="header-anchor" href="#❌-error-de-operacion-ignorar-el-id-de-cuenta-de-equipo" aria-label="Permalink to &quot;❌ Error de operación: Ignorar el ID de cuenta de equipo&quot;">​</a></h3><p><strong>Síntoma de error</strong>: La suscripción Team muestra el uso de otra cuenta</p><p><strong>Causa</strong>: Las suscripciones Team necesitan pasar el ID de cuenta de equipo, de lo contrario se podría estar consultando la cuenta predeterminada.</p><p><strong>Operación correcta</strong>:</p><ul><li>Asegúrate de haber iniciado sesión con la cuenta correcta del equipo en OpenCode</li><li>El token incluirá automáticamente <code>chatgpt_account_id</code></li></ul><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><p>mystatus consulta la cuota llamando a la API oficial de OpenAI:</p><ul><li>Soporta autenticación OAuth (Plus/Team/Pro)</li><li>Muestra ventana principal y ventana secundaria (si existe)</li><li>Barra de progreso visualiza la cuota restante</li><li>Cuenta regresiva muestra el tiempo de restablecimiento</li><li>Detecta automáticamente el token expirado</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la siguiente lección aprenderemos <strong><a href="./../zhipu-usage/">Consulta de cuota de Zhipu AI y Z.ai</a></strong>.</p><p>Aprenderás:</p><ul><li>Qué es el límite de token de 5 horas</li><li>Cómo ver la cuota mensual de MCP</li><li>Advertencias cuando el uso supera el 80%</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de código fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver la ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta de archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Entrada de consulta de cuota de OpenAI</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L207-L236" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>207-236</td></tr><tr><td>Llamada a API de OpenAI</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L132-L155" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>132-155</td></tr><tr><td>Formato de salida</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>Análisis de token JWT</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L64-L73" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>64-73</td></tr><tr><td>Extraer correo de usuario</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L78-L81" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>78-81</td></tr><tr><td>Verificar expiración de token</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L216-L221" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>216-221</td></tr><tr><td>Definición de tipo OpenAIAuthData</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>Constantes</strong>:</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code>: API oficial de consulta de cuota de OpenAI</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>queryOpenAIUsage(authData)</code>: Función principal de consulta de cuota de OpenAI</li><li><code>fetchOpenAIUsage(accessToken)</code>: Llama a la API de OpenAI</li><li><code>formatOpenAIUsage(data, email)</code>: Formatea la salida</li><li><code>parseJwt(token)</code>: Analiza el token JWT (implementación no estándar de biblioteca)</li><li><code>getEmailFromJwt(token)</code>: Extrae el correo del usuario del token</li><li><code>getAccountIdFromJwt(token)</code>: Extrae el ID de cuenta de equipo del token</li></ul></details>`,70)])])}const h=a(r,[["render",s]]);export{m as __pageData,h as default};
